@MainActor
final class TradingViewModel: ObservableObject {
    @Published var orderDraft = OrderDraft()
    @Published var quote: Quote?
    @Published var accountSummary = AccountSummary.mock
    @Published var watchlist: [WatchlistItem] = WatchlistItem.sample
    @Published var preview: OrderPreview?
    @Published var isSubmittingOrder = false
    @Published var showTradeResult = false
    @Published var tradeResultMessage = ""
    @Published var openOrdersCount = 0
    
    private let tradingService = TradingService()
    
    var estimatedOrderValue: Double {
        let qty = Int(orderDraft.quantityText) ?? 0
        let price = orderDraft.type == .market ? (quote?.lastPrice ?? 0) : (Double(orderDraft.limitPriceText) ?? 0)
        return Double(qty) * price
    }
    
    var estimatedFees: Double {
        max(1.0, estimatedOrderValue * 0.0005)
    }
    
    var totalImpact: Double {
        estimatedOrderValue + estimatedFees
    }
    
    var canSubmitOrder: Bool {
        !orderDraft.symbol.isEmpty &&
        (Int(orderDraft.quantityText) ?? 0) > 0 &&
        (orderDraft.type == .market || (Double(orderDraft.limitPriceText) ?? 0) > 0)
    }
    
    func bootstrap() async {
        async let summary = tradingService.fetchAccountSummary()
        async let orders = tradingService.fetchOrders()
        async let quote = tradingService.fetchQuote(symbol: orderDraft.symbol.isEmpty ? "AAPL" : orderDraft.symbol)
        
        self.accountSummary = await summary
        let fetchedOrders = await orders
        self.openOrdersCount = fetchedOrders.filter { $0.status == .open }.count
        self.quote = await quote
    }
    
    func refreshAll() async {
        await bootstrap()
    }
    
    func loadQuote() async {
        guard !orderDraft.symbol.isEmpty else {
            quote = nil
            return
        }
        quote = await tradingService.fetchQuote(symbol: orderDraft.symbol)
    }
    
    func populatePreviewOrder() {
        guard canSubmitOrder else { return }
        let executionPrice = orderDraft.type == .market ? (quote?.lastPrice ?? 0) : (Double(orderDraft.limitPriceText) ?? 0)
        let quantity = Int(orderDraft.quantityText) ?? 0
        preview = OrderPreview(
            symbol: orderDraft.symbol,
            side: orderDraft.side,
            quantity: quantity,
            executionPrice: executionPrice,
            estimatedTotal: Double(quantity) * executionPrice + estimatedFees,
            riskMessage: totalImpact <= accountSummary.buyingPower || orderDraft.side == .sell ? "Approved" : "Insufficient buying power"
        )
    }
    
    func executeTrade() async {
        guard canSubmitOrder else { return }
        isSubmittingOrder = true
        defer { isSubmittingOrder = false }
        
        do {
            let request = SubmitOrderRequest(
                symbol: orderDraft.symbol,
                side: orderDraft.side,
                quantity: Int(orderDraft.quantityText) ?? 0,
                type: orderDraft.type,
                limitPrice: orderDraft.type == .limit ? Double(orderDraft.limitPriceText) : nil
            )
            let response = try await tradingService.submitOrder(request)
            tradeResultMessage = "Order \(response.status.rawValue.capitalized): \(response.orderId)"
            showTradeResult = true
            preview = nil
            openOrdersCount += response.status == .open ? 1 : 0
        } catch {
            tradeResultMessage = error.localizedDescription
            showTradeResult = true
        }
    }
    
    func selectWatchlistSymbol(_ symbol: String) {
        orderDraft.symbol = symbol
        Task { await loadQuote() }
    }
}

