@MainActor
final class OrdersViewModel: ObservableObject {
    @Published var openOrders: [TradeOrder] = []
    @Published var closedOrders: [TradeOrder] = []
    
    private let tradingService = TradingService()
    
    func loadOrders() async {
        let orders = await tradingService.fetchOrders()
        openOrders = orders.filter { $0.status == .open }
        closedOrders = orders.filter { $0.status != .open }
    }
    
    func cancel(order: TradeOrder) async {
        do {
            _ = try await tradingService.cancelOrder(orderId: order.id)
            await loadOrders()
        } catch {
        }
    }
}

struct OrderDraft {
    var symbol: String = "AAPL"
    var side: OrderSide = .buy
    var type: OrderType = .market
    var quantityText: String = "10"
    var limitPriceText: String = ""
}

enum OrderSide: String, Codable, CaseIterable, Identifiable {
    case buy = "Buy"
    case sell = "Sell"
    
    var id: String { rawValue }
}

enum OrderType: String, Codable, CaseIterable, Identifiable {
    case market = "Market"
    case limit = "Limit"
    
    var id: String { rawValue }
}

enum OrderStatus: String, Codable {
    case open
    case filled
    case canceled
    case rejected
}

struct Quote: Codable {
    let symbol: String
    let lastPrice: Double
    let change: Double
    let changePercent: Double
    let bid: Double
    let ask: Double
    let timestamp: Date
}

struct AccountSummary: Codable {
    let buyingPower: Double
    let equity: Double
    let dayPL: Double
    
    static let mock = AccountSummary(buyingPower: 25000, equity: 104350.25, dayPL: 830.64)
}

struct WatchlistItem: Identifiable {
    let id = UUID()
    let symbol: String
    let companyName: String
    let lastPrice: Double
    let change: Double
    
    static let sample: [WatchlistItem] = [
        .init(symbol: "AAPL", companyName: "Apple", lastPrice: 192.24, change: 1.24),
        .init(symbol: "MSFT", companyName: "Microsoft", lastPrice: 421.15, change: -2.11),
        .init(symbol: "NVDA", companyName: "NVIDIA", lastPrice: 901.44, change: 6.42),
        .init(symbol: "AMZN", companyName: "Amazon", lastPrice: 181.20, change: -0.55)
    ]
}

struct OrderPreview {
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let executionPrice: Double
    let estimatedTotal: Double
    let riskMessage: String
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let quantity: Int
    let averageCost: Double
    let marketPrice: Double
    
    var marketValue: Double {
        Double(quantity) * marketPrice
    }
    
    var unrealizedPL: Double {
        Double(quantity) * (marketPrice - averageCost)
    }
}

struct PortfolioSummary: Codable {
    var totalValue: Double = 0
    var cashBalance: Double = 0
    var unrealizedPL: Double = 0
    var realizedPL: Double = 0
}

struct PortfolioResponse: Codable {
    let positions: [Position]
    let summary: PortfolioSummary
}

struct TradeOrder: Codable, Identifiable {
    let id: String
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let type: OrderType
    let status: OrderStatus
    let createdAt: Date
}

struct SubmitOrderRequest: Codable {
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let type: OrderType
    let limitPrice: Double?
}

struct SubmitOrderResponse: Codable {
    let orderId: String
    let status: OrderStatus
}

struct CancelOrderResponse: Codable {
    let success: Bool
}

final class TradingService {
    private let client = APIClient()
    
    func fetchQuote(symbol: String) async -> Quote {
        do {
            return try await client.request(
                path: "/v1/marketdata/quote/\(symbol)",
                method: .get,
                responseType: Quote.self
            )
        } catch {
            return Quote(
                symbol: symbol,
                lastPrice: Double.random(in: 100...500),
                change: Double.random(in: -10...10),
                changePercent: Double.random(in: -3...3),
                bid: Double.random(in: 100...499),
                ask: Double.random(in: 101...500),
                timestamp: Date()
            )
        }
    }
    
    func fetchAccountSummary() async -> AccountSummary {
        do {
            return try await client.request(
                path: "/v1/account/summary",
                method: .get,
                responseType: AccountSummary.self
            )
        } catch {
            return .mock
        }
    }
    
    func fetchPortfolio() async -> PortfolioResponse {
        do {
            return try await client.request(
                path: "/v1/portfolio",
                method: .get,
                responseType: PortfolioResponse.self
            )
        } catch {
            let positions = [
                Position(id: "1", symbol: "AAPL", quantity: 50, averageCost: 176.10, marketPrice: 192.24),
                Position(id: "2", symbol: "MSFT", quantity: 20, averageCost: 390.55, marketPrice: 421.15),
                Position(id: "3", symbol: "NVDA", quantity: 10, averageCost: 820.25, marketPrice: 901.44)
            ]
            let unrealized = positions.reduce(0) { $0 + $1.unrealizedPL }
            let total = positions.reduce(0) { $0 + $1.marketValue } + 12000
            return PortfolioResponse(
                positions: positions,
                summary: PortfolioSummary(totalValue: total, cashBalance: 12000, unrealizedPL: unrealized, realizedPL: 3200)
            )
        }
    }
    
    func fetchOrders() async -> [TradeOrder] {
        do {
            return try await client.request(
                path: "/v1/orders",
                method: .get,
                responseType: [TradeOrder].self
            )
        } catch {
            return [
                TradeOrder(id: "ord_1001", symbol: "AAPL", side: .buy, quantity: 10, type: .market, status: .filled, createdAt: Date()),
                TradeOrder(id: "ord_1002", symbol: "NVDA", side: .buy, quantity: 5, type: .limit, status: .open, createdAt: Date()),
                TradeOrder(id: "ord_1003", symbol: "MSFT", side: .sell, quantity: 8, type: .market, status: .canceled, createdAt: Date())
            ]
        }
    }
    
    func submitOrder(_ request: SubmitOrderRequest) async throws -> SubmitOrderResponse {
        try await client.request(
            path: "/v1/orders",
            method: .post,
            body: request,
            responseType: SubmitOrderResponse.self
        )
    }
    
    func cancelOrder(orderId: String) async throws -> CancelOrderResponse {
        try await client.request(
            path: "/v1/orders/\(orderId)/cancel",
            method: .post,
            responseType: CancelOrderResponse.self
        )
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case delete = "DELETE"
}

enum APIError: LocalizedError {
    case invalidResponse
    case unauthorized
    case serverError(Int)
    case decodingError
    case networkError
    case signingFailed
    
    var errorDescription: String? {
        switch self {
        case .invalidResponse: return "Invalid server response."
        case .unauthorized: return "Unauthorized request."
        case .serverError(let code): return "Server error: \(code)"
        case .decodingError: return "Failed to decode server response."
        case .networkError: return "Network communication error."
        case .signingFailed: return "Secure request signing failed."
        }
    }
}

final class APIClient: NSObject {
    private let session: URLSession
    private let secureStore = SecureStore()
    private let signer = RequestSigner()
    private let environmentProvider = EnvironmentProvider.shared
    
    override init() {
        let configuration = URLSessionConfiguration.ephemeral
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 15
        configuration.timeoutIntervalForResource = 30
        self.session = URLSession(configuration: configuration, delegate: nil, delegateQueue: nil)
        super.init()
    }
    
    func request<T: Decodable, U: Encodable>(
        path: String,
        method: HTTPMethod,
        body: U? = nil,
        responseType: T.Type
    ) async throws -> T {
        var request = try buildRequest(path: path, method: method, body: body)
        try signer.sign(&request)
        
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }
        
        switch http.statusCode {
        case 200...299:
            break
        case 401:
            throw APIError.unauthorized
        default:
            throw APIError.serverError(http.statusCode)
        }
        
        do {
            return try JSONDecoder.api.decode(T.self, from: data)
        } catch {
            throw APIError.decodingError
        }
    }
    
    func request<T: Decodable>(
        path: String,
        method: HTTPMethod,
        responseType: T.Type
    ) async throws -> T {
        try await request(path: path, method: method, body: Optional<String>.none, responseType: responseType)
    }
    
    private func buildRequest<U: Encodable>(path: String, method: HTTPMethod, body: U?) throws -> URLRequest {
        let baseURL = environmentProvider.current.baseURL
        let url = baseURL.appendingPathComponent(path)
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue("iOS", forHTTPHeaderField: "X-Client-Platform")
        request.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-ID")
        
        if let token = secureStore.authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body {
            request.httpBody = try JSONEncoder.api.encode(body)
        }
        
        return request
    }
}

final class EnvironmentProvider {
    static let shared = EnvironmentProvider()
    var current: APIEnvironment = .staging
    private init() {}
}

final class RequestSigner {
    private let secureStore = SecureStore()
    
    func sign(_ request: inout URLRequest) throws {
        guard let privateKey = secureStore.privateKey else {
            throw APIError.signingFailed
        }
        
        let method = request.httpMethod ?? "GET"
        let path = request.url?.path ?? "/"
        let timestamp = ISO8601DateFormatter().string(from: Date())
        let bodyString = request.httpBody.flatMap { String(data: $0, encoding: .utf8) } ?? ""
        let payload = "\(method)\n\(path)\n\(timestamp)\n\(bodyString)"
        let signature = try privateKey.signature(for: Data(payload.utf8))
        let signatureString = Data(signature.derRepresentation).base64EncodedString()
        
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        request.setValue(signatureString, forHTTPHeaderField: "X-Signature")
        request.setValue(secureStore.publicKeyIdentifier, forHTTPHeaderField: "X-Key-ID")
    }
}

final class SecureStore {
    private let keyTag = "com.investplatform.devicekey"
    private let authTokenKey = "com.investplatform.authtoken"
    
    init() {
        generateKeyIfNeeded()
        if authToken == nil {
            authToken = "demo-auth-token"
        }
    }
    
    var hasDeviceKey: Bool {
        privateKey != nil
    }
    
    var authToken: String? {
        get {
            let query: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrAccount as String: authTokenKey,
                kSecReturnData as String: true,
                kSecMatchLimit as String: kSecMatchLimitOne
            ]
            
            var item: CFTypeRef?
            let status = SecItemCopyMatching(query as CFDictionary, &item)
            guard status == errSecSuccess, let data = item as? Data else { return nil }
            return String(data: data, encoding: .utf8)
        }
        set {
            let data = (newValue ?? "").data(using: .utf8) ?? Data()
            let query: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrAccount as String: authTokenKey
            ]
            SecItemDelete(query as CFDictionary)
            let add: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrAccount as String: authTokenKey,
                kSecValueData as String: data
            ]
            SecItemAdd(add as CFDictionary, nil)
        }
    }
    
    var privateKey: P256.Signing.PrivateKey? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: keyTag.data(using: .utf8)!,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecReturnData as String: true
        ]
        
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess, let data = item as? Data else { return nil }
        return try? P256.Signing.PrivateKey(rawRepresentation: data)
    }
    
    var publicKeyIdentifier: String {
        guard let key = privateKey else { return "unknown-device-key" }
        let digest = SHA256.hash(data: key.publicKey.rawRepresentation)
        return digest.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    private func generateKeyIfNeeded() {
        guard privateKey == nil else { return }
        let key = P256.Signing.PrivateKey()
        let data = key.rawRepresentation
        let add: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: keyTag.data(using: .utf8)!,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(add as CFDictionary, nil)
    }
}

final class NetworkMonitor: ObservableObject {
    @Published var isConnected: Bool = true
}

extension JSONDecoder {
    static var api: JSONDecoder {
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return decoder
    }
}

extension JSONEncoder {
    static var api: JSONEncoder {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        return encoder
    }
}

extension Double {
    var currencyString: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }
}